-- 2. Canterbury District × SEO
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'seo',
  'canterbury-district',
  'Canterbury District presents one of the most complex local SEO landscapes in Kent. The district contains three distinct search ecosystems: Canterbury city, where tourism, heritage, and university-related queries dominate; Whitstable, where food, lifestyle, and independent retail searches surge at weekends; and Herne Bay, where residential service searches follow traditional patterns. A business that ranks well in Canterbury city may be completely invisible in Whitstable searches just eight miles away. Google treats these as distinct local markets with separate Map Pack results, different competitor sets, and unique search intent patterns. Our SEO campaigns are built to navigate this complexity, targeting the specific towns, postcodes, and search behaviours that matter to your business across the district.',
  'Canterbury District''s search landscape is shaped by three overlapping audience segments. Tourism generates high-volume seasonal searches around the Cathedral, St Augustine''s Abbey, Canterbury Tales, and the historic city centre. The three universities create a cyclical demand pattern with surges at the start of each academic term. Whitstable has developed an outsized online search profile driven by its food and lifestyle reputation, with weekend visitors from London researching restaurants and activities before making the hour-long train journey. Herne Bay''s search patterns are more traditional, dominated by residential services and local trades. The villages of Bridge, Chartham, and Sturry generate lower-volume but high-conversion searches for nearby services.',
  'SEO competition varies dramatically across the Canterbury District. In Canterbury city, tourism keywords are fiercely contested by national platforms like TripAdvisor, Booking.com, and Visit Kent. Whitstable restaurant and activity searches are highly competitive due to the town''s national profile. Herne Bay and the surrounding villages are significantly less contested, offering faster ranking opportunities. Very few businesses optimise for cross-district visibility, meaning a coordinated SEO strategy targeting all three towns simultaneously represents a major competitive advantage.',
  'We treat Canterbury District SEO as a multi-location campaign. Each town within the district gets its own keyword research, Google Business Profile optimisation, and content strategy. A Canterbury city restaurant needs different SEO than a Whitstable gallery or a Herne Bay plumber. We build location-specific landing pages, optimise multiple Google Business Profiles where appropriate, and create content that demonstrates genuine knowledge of each area within the district.',
  '{"population": 165000, "growth": "Tourism and university cycles drive seasonal search patterns", "business_districts": ["Canterbury City Centre", "Whitstable", "Herne Bay", "Bridge", "Chartham", "Sturry"], "key_fact": "Three distinct local search ecosystems within one district"}',
  '[{"title": "Ranking in Canterbury city but invisible in Whitstable and Herne Bay", "description": "Google treats Canterbury, Whitstable, and Herne Bay as separate local markets. A business that ranks well for Canterbury searches may not appear at all when residents of Whitstable or Herne Bay search for the same service. Without a multi-location SEO strategy, you are only visible to a fraction of the district''s 165,000 residents."}, {"title": "Tourism platforms dominating Canterbury heritage and hospitality searches", "description": "TripAdvisor, Booking.com, Expedia, and Visit Kent dominate the first page for Canterbury tourism keywords. Independent Canterbury businesses that rely on organic search for bookings are pushed below the fold, losing the majority of clicks to aggregator platforms that take commissions and control the customer relationship."}, {"title": "Whitstable''s national profile attracting competition from outside the district", "description": "Whitstable''s food and lifestyle reputation means London-based SEO agencies and national restaurant platforms actively target Whitstable keywords. Local independent businesses face competition not just from neighbouring shops but from well-funded national competitors optimising for the same Whitstable search terms."}]',
  '[{"title": "Multi-town SEO strategy covering the full Canterbury District", "description": "We build separate but coordinated SEO campaigns for Canterbury city, Whitstable, Herne Bay, and surrounding villages. Each location gets dedicated keyword research, localised content, and Google Business Profile optimisation. Your business gains visibility across the entire district rather than just one town."}, {"title": "Tourism-resistant ranking strategy for Canterbury hospitality", "description": "We help Canterbury hospitality businesses compete against national aggregator platforms through a combination of direct booking optimisation, rich snippet markup for events and menus, aggressive Google Business Profile management, and local backlink building from Kent tourism sites that carry genuine authority."}, {"title": "Seasonal content strategy aligned to district demand cycles", "description": "Canterbury District''s search patterns follow tourism seasons, university terms, and Whitstable''s event calendar. We build content calendars that anticipate these surges, publishing optimised pages and posts before demand peaks so your site is already ranking when search volume increases."}]',
  '[{"question": "Can you help me rank in all three towns across Canterbury District?", "answer": "Yes. We build multi-location SEO campaigns that target Canterbury city, Whitstable, and Herne Bay as separate but coordinated markets. This includes individual Google Business Profiles where appropriate, location-specific landing pages, and targeted content for each area. The strategy ensures visibility across the full district."}, {"question": "How competitive are Canterbury city tourism keywords?", "answer": "Extremely competitive. National platforms like TripAdvisor and Booking.com dominate many Canterbury tourism terms. However, specific local keywords, long-tail queries, and Google Map Pack positions remain achievable with a focused strategy. We identify the terms where local businesses can realistically compete and win."}, {"question": "Is it worth targeting Whitstable keywords separately from Canterbury?", "answer": "Absolutely. Google treats Whitstable as a distinct local market with its own Map Pack results. Many customers searching for Whitstable businesses are weekend visitors from London with high spending intent. Ranking for Whitstable terms captures a premium audience that Canterbury-only SEO misses entirely."}, {"question": "How do university term times affect SEO strategy?", "answer": "The arrival of over 30,000 students at the start of each term creates search surges for accommodation, food, entertainment, and services. We plan content and optimisation around the academic calendar so your business is visible when these demand spikes occur. During vacations, we shift focus to tourism and resident-based searches."}]',
  'authority'
)
