-- 6. Canterbury District × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'canterbury-district',
  'Social media in Canterbury District operates across strikingly different ecosystems depending on which part of the district your business serves. Canterbury city''s social landscape is dominated by tourism, university life, and heritage events. Whitstable has a nationally engaged Instagram community built around food, coastal lifestyle, and independent shopping. Herne Bay''s social media is more community-focused, with Facebook groups driving local trade recommendations. A social media presence set up without understanding these differences wastes effort and misses the audiences that matter. We build and optimise social media profiles for Canterbury District businesses that are configured for the specific platform, audience, and content style that drives results in your part of the district.',
  'Canterbury District''s social media landscape reflects its diverse communities. Canterbury city businesses benefit from tagging in cathedral, university, and tourism content that reaches international audiences. Whitstable''s Instagram presence is remarkably strong for a town its size, driven by food photography, coastal scenery, and lifestyle content that attracts followers from across the country. Herne Bay''s social activity centres on Facebook community groups where residents recommend tradespeople, restaurants, and local services. The university student population is active on Instagram, TikTok, and Reddit, creating additional channels for businesses targeting the under-25 demographic.',
  'Social media quality across Canterbury District mirrors the broader brand quality divide. Whitstable businesses tend to have strong Instagram presences that match the town''s visual culture. Canterbury city tourism businesses increasingly maintain professional profiles across multiple platforms. Herne Bay and village businesses have significantly lower social media adoption, with many having dormant or absent profiles. The gap represents both a challenge and an opportunity for businesses willing to invest in proper setup.',
  'We configure social media profiles for Canterbury District businesses based on where their customers actually engage online. A Canterbury city tourism business gets Instagram and TripAdvisor integration for visual storytelling. A Whitstable restaurant gets Instagram-first setup with professional food photography templates. A Herne Bay tradesperson gets Facebook optimised for community group engagement. Every profile is branded consistently and optimised for the discovery methods specific to each platform and audience.',
  '{"population": 165000, "growth": "Whitstable''s Instagram presence punches above its weight nationally", "business_districts": ["Canterbury City Centre", "Whitstable", "Herne Bay", "University campuses"], "key_fact": "Three distinct social media ecosystems within one district"}',
  '[{"title": "Same social media approach across fundamentally different Canterbury District audiences", "description": "A Canterbury District business posting the same content to Facebook, Instagram, and LinkedIn without adapting for audience or platform reaches nobody effectively. The international tourist audience on Instagram, the Herne Bay mum seeking a plumber on Facebook, and the Canterbury professional on LinkedIn each require different content, tone, and format."}, {"title": "Whitstable businesses with Instagram presence that does not convert", "description": "Many Whitstable businesses have Instagram accounts with attractive food or lifestyle photography but no clear conversion path. Beautiful images generate likes from people in London, Bristol, and beyond who may never visit. Without a strategy connecting social presence to actual bookings or sales, engagement metrics mask commercial failure."}, {"title": "Herne Bay businesses invisible in local Facebook recommendation threads", "description": "When Herne Bay residents post in community Facebook groups asking for a plumber, electrician, or restaurant recommendation, businesses without properly set up Facebook pages cannot be tagged, linked, or found. They are excluded from the most powerful word-of-mouth channel in their local market."}]',
  '[{"title": "Platform-matched social setup for each Canterbury District audience", "description": "We build social profiles configured for the platform that matters most to your specific audience. Canterbury tourism businesses get Instagram and TripAdvisor integration. Whitstable hospitality gets Instagram with booking link optimisation. Herne Bay services get Facebook pages built for community group engagement. Every setup targets where your actual customers spend their time."}, {"title": "Conversion-focused Whitstable Instagram with booking integration", "description": "For Whitstable businesses, we go beyond attractive imagery. We set up Instagram profiles with direct booking links, shoppable posts, story highlights organised by offering, and call-to-action buttons that convert followers into customers. Every element is designed to turn Whitstable''s strong Instagram engagement into measurable revenue."}, {"title": "Community-group-optimised Facebook for Herne Bay and village businesses", "description": "We build Facebook business pages for Herne Bay, Bridge, Chartham, and Sturry businesses that are optimised for community group engagement. Professional branding, complete service information, portfolio galleries, and review collection systems ensure that when a resident tags or recommends your business, the profile they find converts their interest into an enquiry."}]',
  '[{"question": "Which social media platforms should my Canterbury District business prioritise?", "answer": "It depends entirely on your audience and location. Canterbury city tourism businesses thrive on Instagram and Google. Whitstable hospitality needs Instagram-first strategy. Herne Bay trades need Facebook for community group visibility. B2B firms in Canterbury need LinkedIn. We audit your specific audience and recommend the platforms that will actually generate returns."}, {"question": "How do I make my Whitstable Instagram account generate actual bookings?", "answer": "Beautiful content alone does not convert. We set up your profile with direct booking links, optimised call-to-action buttons, story highlights that showcase your offering, and a content template system that balances aspirational imagery with clear commercial messaging. Every post has a purpose beyond likes."}, {"question": "Can you set up social media for a business in a Canterbury District village?", "answer": "Yes. Businesses in Bridge, Chartham, Sturry, Blean, and other villages benefit enormously from Facebook presence that connects them to the wider Canterbury District community. We set up profiles optimised for local discovery and community group engagement, extending your reach beyond the village to the full district."}, {"question": "Do you create content or just set up the profiles?", "answer": "This service focuses on professional setup, branding, and optimisation of your social media profiles. We also provide content templates, posting guides, and a strategy document so you can maintain your presence effectively. Ongoing content creation and management is available as a separate service."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
  success_approach = EXCLUDED.success_approach,
  local_stats = EXCLUDED.local_stats,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs,
  layout_variant = EXCLUDED.layout_variant;

-- 7. Canterbury District × Digital Marketing
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'digital-marketing',
  'canterbury-district',
  'Canterbury District offers one of the richest digital marketing opportunities in Kent, but also one of the most complex. With 165,000 residents, three universities generating over 30,000 students, millions of annual heritage tourists, and Whitstable''s nationally recognised foodie destination pulling weekend visitors from London, the district contains multiple overlapping audiences that require fundamentally different marketing approaches. A Google Ads campaign targeting Canterbury city heritage tourists looks nothing like a Facebook campaign reaching Whitstable weekend visitors or an Instagram promotion targeting university students. The businesses that thrive in Canterbury District are those that understand these audience segments and market to each one distinctly. Our digital marketing campaigns are built from granular knowledge of how each segment searches, browses, and makes purchasing decisions across the district.',
  'Canterbury District''s digital marketing landscape is defined by audience complexity. International tourists plan Canterbury visits weeks in advance using Google search and TripAdvisor. London day-trippers to Whitstable research on social media and make same-week decisions. University students discover businesses through Instagram, TikTok, and peer recommendations. Herne Bay residents follow traditional local search patterns for trades and services. Canterbury''s professional services sector operates in a B2B environment with LinkedIn and search-driven lead generation. The district''s geographic spread from coast to inland villages adds location-targeting complexity to every campaign.',
  'Digital advertising competition in Canterbury District varies by segment. Canterbury city tourism keywords are among the most expensive in Kent due to national platform competition. Whitstable hospitality terms have rising costs driven by the town''s growing popularity. Herne Bay and village-based service keywords remain relatively affordable with strong return potential. Facebook and Instagram advertising across the district benefits from precise geographic targeting but requires segment-specific creative to avoid wasted spend.',
  'We build Canterbury District digital marketing campaigns as multi-segment strategies. Each audience, tourists, weekend visitors, students, residents, and B2B clients, gets its own targeting, messaging, and conversion pathway. Google Ads capture high-intent searches with location-specific ad copy. Social media campaigns reach Whitstable''s lifestyle audience and Canterbury''s student population with platform-native creative. Every campaign tracks leads back to the specific segment and channel that generated them.',
  '{"population": 165000, "growth": "Multiple high-value audience segments in one district", "business_districts": ["Canterbury City Centre", "Whitstable", "Herne Bay", "University campuses", "Canterbury Business Park"], "key_fact": "Tourism, students, and weekend visitors create three distinct marketing audiences"}',
  '[{"title": "Marketing budget wasted on the wrong Canterbury District audience", "description": "Running a single digital campaign across Canterbury District reaches tourists, students, residents, and weekenders simultaneously. But a message designed for Canterbury heritage tourists has zero relevance to a Herne Bay homeowner searching for a plumber. Without audience segmentation, the majority of your marketing budget reaches people who will never become your customers."}, {"title": "Whitstable marketing competing with national food and lifestyle brands", "description": "Whitstable''s national reputation means local businesses compete for digital attention against food magazines, travel publications, and London-based influencers who cover the town. A Whitstable restaurant running ads without sophisticated targeting and creative strategy gets drowned out by content from brands with far larger budgets."}, {"title": "No tracking to identify which Canterbury District channels generate revenue", "description": "Most Canterbury District businesses cannot attribute their customers to specific marketing channels. They run Google Ads, post on social media, and list on tourism directories without knowing which activity generates bookings or enquiries. This makes budget allocation guesswork and improvement impossible."}]',
  '[{"title": "Multi-segment campaigns for Canterbury District''s diverse audiences", "description": "We build separate campaign streams for each audience segment relevant to your business. Canterbury tourists see search ads with heritage and booking messaging. Whitstable weekenders see Instagram and Facebook campaigns with lifestyle creative. Herne Bay residents see Google Ads for local services. Students see platform-native content on Instagram and TikTok. Each segment gets tailored messaging and a dedicated conversion path."}, {"title": "Geo-targeted advertising across the district''s distinct markets", "description": "We use precise geographic targeting to reach customers in specific parts of Canterbury District. Postcode-level Google Ads ensure your budget reaches only searchers in your service area. Facebook campaigns target residents of specific towns and villages. Tourism campaigns target people planning visits to Canterbury from outside the district."}, {"title": "Full attribution tracking from ad click to paying customer", "description": "Every Canterbury District campaign includes comprehensive conversion tracking. You know exactly which audience segment, platform, and ad variation generated each lead. Monthly reporting shows your cost per enquiry, cost per customer, and return on investment broken down by campaign stream, enabling data-driven budget decisions."}]',
  '[{"question": "How do you handle the different audiences across Canterbury District?", "answer": "We treat each audience segment as a separate campaign stream with its own targeting, messaging, creative, and conversion tracking. A Canterbury tourism campaign runs independently from a Herne Bay services campaign, with different budgets, platforms, and performance metrics. This prevents audience crossover and budget waste."}, {"question": "What budget is needed for digital marketing across Canterbury District?", "answer": "Budget requirements depend on which segments you target and how competitive your sector is. Canterbury tourism keywords are expensive, while Herne Bay service terms are affordable. Most Canterbury District businesses see meaningful results from eight hundred to two thousand pounds monthly in ad spend, plus management fees. We provide segment-specific forecasts before you commit."}, {"question": "Can you target Whitstable weekend visitors from London specifically?", "answer": "Yes. We use geographic and behavioural targeting to reach people in London and the South East who have shown interest in Whitstable, coastal day trips, or food tourism. These pre-visit campaigns capture customers during the planning phase, driving direct bookings rather than walk-in uncertainty."}, {"question": "How do you market to Canterbury university students?", "answer": "Students respond to platform-native content on Instagram, TikTok, and peer recommendation platforms. We build campaigns using creative formats and messaging that resonate with the student demographic, timed around term dates, freshers'' weeks, and key university calendar events. Student discount and loyalty offers are integrated into the conversion path."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
  success_approach = EXCLUDED.success_approach,
  local_stats = EXCLUDED.local_stats,
  pain_points = EXCLUDED.pain_points,
