-- 8. Canterbury District × Workwear & Print
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'workwear-print',
  'canterbury-district',
  'Canterbury District''s business community spans heritage tourism in the city centre, independent retail along Whitstable''s harbour, seaside hospitality in Herne Bay, and trades serving residential customers across the district''s villages. Each of these contexts demands workwear and print materials that fit the environment. A Canterbury city walking tour guide needs branded outerwear that projects heritage credibility. A Whitstable deli needs staff aprons that match the artisan aesthetic customers expect. A Herne Bay builder needs durable branded hi-vis that builds trust on residential doorsteps. We provide branded workwear and printed materials tailored to the specific commercial environment where Canterbury District businesses operate, turning every staff member and printed item into a professional marketing asset.',
  'Canterbury District''s physical business environment is uniquely varied. The city centre''s medieval streets and conservation area create a setting where branded staff and materials must look premium yet appropriate. Whitstable''s harbour and high street favour an artisan, independent aesthetic where presentation standards are set by the town''s creative community. Herne Bay''s residential and commercial areas require practical, trust-building professional presentation. The surrounding villages generate outdoor and agricultural work where durability and visibility are paramount. The tourism sector adds a dimension of branded merchandise and visitor-facing materials that most Kent districts lack.',
  'Workwear and print standards across Canterbury District are highest in Whitstable, where the independent business culture drives investment in branded aprons, packaging, and print materials. Canterbury city''s tourism sector is increasingly professional in its staff presentation. Herne Bay and village-based trades have lower workwear adoption, with many businesses still operating in unmarked clothing. The overall standard is rising, and businesses without branded workwear increasingly stand out for the wrong reasons.',
  'We supply Canterbury District businesses with workwear and print materials designed for their specific operating environment. Canterbury city tourism businesses get heritage-appropriate branded outerwear and visitor materials. Whitstable independents get artisan-quality aprons, packaging, and print that matches the town''s creative standards. Herne Bay trades get durable, branded workwear that builds trust with residential customers. Every item is produced to brand guidelines and delivered ready to use.',
  '{"population": 165000, "growth": "Tourism sector driving demand for branded merchandise and staff presentation", "business_districts": ["Canterbury City Centre", "Whitstable Harbour", "Whitstable High Street", "Herne Bay", "Canterbury Industrial Park"], "key_fact": "Whitstable''s artisan culture sets high standards for branded materials"}',
  '[{"title": "Canterbury tourism staff looking unprofessional alongside heritage attractions", "description": "Canterbury''s Cathedral, museums, and heritage attractions set a premium standard for visitor experience. Tourism businesses with unbranded or poorly branded staff stand out as unprofessional in this context. International visitors judge credibility instantly, and staff without clear branded workwear undermine the premium positioning that Canterbury''s heritage demands."}, {"title": "Whitstable independents needing artisan-quality branded materials", "description": "On Whitstable''s high street, branded packaging, staff aprons, and printed materials are part of the customer experience. A deli with plain paper bags or a cafe with unbranded mugs looks out of step with the town''s curated independent identity. Customers who travel from London to shop in Whitstable expect a premium presentation they cannot get at a chain."}, {"title": "Herne Bay and village trades without branded workwear losing trust", "description": "Residential customers in Herne Bay, Bridge, Chartham, and surrounding villages are cautious about who they let into their homes. A tradesperson in unmarked clothing with no printed materials to leave behind fails the basic trust test. Branded workwear, vehicle graphics, and professional printed cards make the difference between a confident welcome and a suspicious response."}]',
  '[{"title": "Heritage-appropriate workwear for Canterbury city businesses", "description": "We supply branded outerwear, uniforms, and staff presentation materials that project the premium quality Canterbury''s heritage context demands. Embroidered jackets, branded name badges, and professionally printed visitor materials that look appropriate alongside the Cathedral and King''s Mile, not cheap or out of place."}, {"title": "Artisan-quality branded materials for Whitstable independents", "description": "We produce printed packaging, branded aprons, embroidered uniforms, and bespoke print materials that match Whitstable''s creative standards. From custom paper bags and food packaging to screen-printed staff tees and hand-finished menus, every item reflects the artisan quality that Whitstable''s discerning customers expect."}, {"title": "Durable branded workwear for trades across the district", "description": "For tradespeople covering Canterbury District from Herne Bay to the rural villages, we supply embroidered and printed workwear built to last. Hi-vis, polo shirts, hoodies, and fleeces all professionally branded with your logo. Combined with printed callback cards and vehicle graphics, your team projects professionalism at every job site."}]',
  '[{"question": "Can you produce workwear suitable for Canterbury city''s conservation area?", "answer": "Yes. We understand the presentation standards expected in Canterbury''s heritage context and supply workwear that projects quality appropriate to the setting. Embroidered rather than screen-printed, muted or heritage colours where appropriate, and professional finishes that complement rather than clash with the city centre environment."}, {"question": "Do you supply branded packaging for Whitstable food businesses?", "answer": "Absolutely. We produce custom printed bags, boxes, wrapping, and food packaging for Whitstable''s independent food retailers and restaurants. All items are produced to brand guidelines and can include custom illustrations, logos, and finishing details that reflect the artisan quality Whitstable customers expect."}, {"question": "What is the minimum order for Canterbury District workwear?", "answer": "We can supply as few as five items for sole traders and small businesses. Larger teams across the district benefit from volume pricing on orders of twenty or more items. We hold your logo and brand files on record for convenient reordering as your team grows or workwear needs replacing."}, {"question": "Can you supply branded merchandise for Canterbury tourism businesses?", "answer": "Yes. Beyond staff workwear, we produce branded merchandise including tote bags, caps, pens, postcards, and promotional items for Canterbury tourism businesses. These items generate additional revenue while marketing your business to visitors who take them home as souvenirs."}]',
  'operational'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
  success_approach = EXCLUDED.success_approach,
  local_stats = EXCLUDED.local_stats,
  pain_points = EXCLUDED.pain_points,
