-- 9. Canterbury District × AI Chatbots
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'ai-chatbots',
  'canterbury-district',
  'Canterbury District businesses face a communication challenge that few other Kent areas share: their customers speak different languages, browse at different times, and ask fundamentally different questions depending on whether they are a Japanese tourist researching Canterbury Cathedral, a London foodie planning a Whitstable weekend, a University of Kent student looking for part-time work, or a Herne Bay resident needing an emergency plumber. Staffing a reception or phone line to handle this diversity around the clock is impossible for small businesses. An AI chatbot trained on your specific services, FAQs, and customer types engages every visitor in natural conversation the moment they arrive on your site, regardless of when they visit or what language they speak, qualifying their needs and capturing their details so you wake up to a list of pre-qualified leads.',
  'Canterbury District''s customer communication patterns are shaped by its diverse audiences. International tourists browse Canterbury attraction and accommodation websites across every time zone, with significant traffic from Japan, the United States, France, and Germany. Whitstable''s weekend visitor traffic peaks on Thursday and Friday evenings as Londoners plan their Saturday trips. University students communicate primarily through messaging and expect instant responses at all hours. Herne Bay and village residents follow more traditional daytime browsing patterns but increasingly expect out-of-hours availability for urgent trades enquiries.',
  'AI chatbot adoption across Canterbury District is negligible. A small number of Canterbury city hotels use basic live chat during reception hours, but virtually no businesses offer intelligent automated conversation. Whitstable restaurants rely on phone reservations and third-party platforms. Herne Bay trades have no real-time engagement tools. The first businesses in each sector to deploy effective AI chatbots across Canterbury District will capture a significant volume of enquiries that every competitor currently misses.',
  'We build AI chatbots for Canterbury District businesses trained on your specific service offering, location context, and customer types. A Canterbury accommodation chatbot handles enquiries in multiple languages and integrates with your booking system. A Whitstable restaurant chatbot manages reservation requests during the Thursday evening planning rush. A Herne Bay trades chatbot qualifies emergency versus routine enquiries and routes accordingly. Every chatbot is designed for mobile-first interaction to match how Canterbury District''s visitors actually browse.',
  '{"population": 165000, "growth": "International tourism creating multilingual communication needs", "business_districts": ["Canterbury City Centre", "Whitstable", "Herne Bay", "University campuses"], "key_fact": "Time zone diversity from international tourism means enquiries arrive around the clock"}',
  '[{"title": "International tourist enquiries lost to time zone differences", "description": "A potential visitor in Tokyo researches Canterbury Cathedral accommodation at midday Japanese time, which is three in the morning in Kent. Your website offers a contact form. They fill it in, but by the time you respond twelve hours later, they have booked with a competitor whose site offered instant availability and booking. Multiplied across visitors from every time zone, the lost revenue is substantial."}, {"title": "Whitstable reservation requests piling up on Thursday evenings", "description": "Whitstable''s weekend visitor economy means Thursday and Friday evenings generate a concentrated surge of reservation enquiries. If your restaurant or activity business cannot respond instantly during this planning window, those visitors book elsewhere. A phone line and email inbox cannot handle the volume during peak planning hours."}, {"title": "Student enquiries requiring instant response across messaging platforms", "description": "Canterbury''s thirty thousand students expect immediate answers. They browse a business website, have a question about pricing or availability, and want an instant response. If your site offers only a contact form or phone number, they leave and ask in a group chat instead, where a competitor who has engaged them first will get recommended."}]',
  '[{"title": "Multilingual AI chatbot for Canterbury''s international visitors", "description": "Our AI chatbots for Canterbury tourism businesses detect visitor language preference and respond naturally in English, French, German, Japanese, and other key languages. Visitors get instant, knowledgeable answers to questions about your services, availability, and location. Bookings and enquiries are captured automatically regardless of language or time zone."}, {"title": "Reservation-trained chatbot for Whitstable hospitality", "description": "We build chatbots specifically for Whitstable restaurants, cafes, and activity providers that handle the Thursday-to-Saturday reservation surge. The chatbot checks availability, takes bookings, manages waiting lists, and answers menu or event questions. It handles the volume peaks that would overwhelm a phone line, capturing every potential booking."}, {"title": "Service-qualified chatbot for Herne Bay and district trades", "description": "For trades and service businesses across Canterbury District, our chatbot qualifies every enquiry by type, urgency, location, and budget. Emergency requests receive immediate flagging and callback scheduling. Routine enquiries enter your standard pipeline with all details captured. You see a prioritised list of qualified leads each morning instead of a cluttered inbox."}]',
  '[{"question": "Can an AI chatbot really handle multiple languages for Canterbury tourism?", "answer": "Yes. Modern AI chatbots hold natural conversations in dozens of languages. We train yours on your specific service information in each target language so it provides accurate, knowledgeable responses to international visitors. The chatbot detects language preference automatically and switches seamlessly."}, {"question": "How does the chatbot integrate with my Whitstable restaurant booking system?", "answer": "We connect the chatbot directly to your reservation management platform, whether that is ResDiary, OpenTable, or a custom system. The chatbot checks real-time availability, takes bookings that appear directly in your system, and manages waiting lists. Customers get instant confirmation without you lifting a finger."}, {"question": "Will the chatbot replace my phone line?", "answer": "No. The chatbot handles website visitors who prefer digital interaction, which is an increasing majority. Customers who want to phone still call you directly. The chatbot captures the significant portion of visitors who would otherwise leave your site without making contact because they did not want to call or wait for an email reply."}, {"question": "How quickly can you deploy a chatbot for my Canterbury District business?", "answer": "Most chatbot deployments go live within one to two weeks. The first week covers training the AI on your services, FAQs, location details, and booking systems. The second week involves testing, refinement, and website integration. For multilingual chatbots, add an additional week for language-specific training and quality assurance."}]',
  'authority'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
